      sortNotif: getColIndex(dossierColMap, dossierHeaderKeys.sortNotif),
      avisCurateur: getColIndex(dossierColMap, dossierHeaderKeys.avisCurateur),
      pvPlice: getColIndex(dossierColMap, dossierHeaderKeys.pvPlice),
      certificatNonAppelStatus: getColIndex(dossierColMap, dossierHeaderKeys.certificatNonAppelStatus),
      notificationStatus: getColIndex(dossierColMap, dossierHeaderKeys.notificationStatus),
      attDelegationOuDelegat: getColIndex(dossierColMap, dossierHeaderKeys.attDelegationOuDelegat),
      huissier: getColIndex(dossierColMap, dossierHeaderKeys.huissier),
      dateExecution: getColIndex(dossierColMap, dossierHeaderKeys.dateExecution),
      miseAPrix: getColIndex(dossierColMap, dossierHeaderKeys.miseAPrix),
      plie: getColIndex(dossierColMap, dossierHeaderKeys.plie),
      pubAuJournal: getColIndex(dossierColMap, dossierHeaderKeys.pubAuJournal),
      plieCmd: getColIndex(dossierColMap, dossierHeaderKeys.plieCmd),
      lotDu: getColIndex(dossierColMap, dossierHeaderKeys.lotDu),
      debiteurEp: getColIndex(dossierColMap, dossierHeaderKeys.debiteurEp),
      debiteurAp: getColIndex(dossierColMap, dossierHeaderKeys.debiteurAp),
      cinRc: getColIndex(dossierColMap, dossierHeaderKeys.cinRc),
      rib: getColIndex(dossierColMap, dossierHeaderKeys.rib),
      banqueFr: getColIndex(dossierColMap, dossierHeaderKeys.banqueFr),
      banqueAr: getColIndex(dossierColMap, dossierHeaderKeys.banqueAr),
      adresseBranche: getColIndex(dossierColMap, dossierHeaderKeys.adresseBranche),
      avocat: getColIndex(dossierColMap, dossierHeaderKeys.avocat),
      sortPle: getColIndex(dossierColMap, dossierHeaderKeys.sortPle),
      notifBanque: getColIndex(dossierColMap, dossierHeaderKeys.notifBanque),
      notifDebiteur: getColIndex(dossierColMap, dossierHeaderKeys.notifDebiteur),
      notificationSort: getColIndex(dossierColMap, dossierHeaderKeys.notificationSort),
      notificationNo: getColIndex(dossierColMap, dossierHeaderKeys.notificationNo),
      executionNo: getColIndex(dossierColMap, dossierHeaderKeys.executionNo),
      dateDepot: getColIndex(dossierColMap, dossierHeaderKeys.dateDepot),
      delegation: getColIndex(dossierColMap, dossierHeaderKeys.delegation),
      huissier: getColIndex(dossierColMap, dossierHeaderKeys.huissier),
      certificatNonAppelStatus: getColIndex(dossierColMap, dossierHeaderKeys.certificatNonAppelStatus),
      sortExecution: getColIndex(dossierColMap, dossierHeaderKeys.sortExecution),
      sort: getColIndex(dossierColMap, dossierHeaderKeys.sort),
      sortOrd: getColIndex(dossierColMap, dossierHeaderKeys.sortOrd),
      tribunal: getColIndex(dossierColMap, dossierHeaderKeys.tribunal),
