async function closeFactureDocumentPreviewModal(){
  if(facturePreviewEdited){
    await saveFacturePreviewEdits();
  }
  const modal = $('factureDocumentPreviewModal');
  const content = $('factureDocumentPreviewContent');
  currentFacturePreviewRecord = null;
  setFacturePreviewEditMode(false);
  facturePreviewEdited = false;
  facturePreviewLastFocusedCell = null;
  facturePreviewActiveEditKey = '';
  if(content) content.innerHTML = '';
  if(modal) modal.style.display = 'none';
}

function getFacturePreviewEditableNodes(){
  const content = $('factureDocumentPreviewContent');
  if(!content) return [];
  return [...content.querySelectorAll('.facture-sheet td, .facture-sheet th, .facture-sheet div')];
}

function markFacturePreviewEdited(){
  facturePreviewEdited = true;
  $('factureDocumentPreviewContent')?.classList.add('is-edited');
}

function getFacturePreviewCurrentTranche(){
  if(currentFacturePreviewRecord?.tranche){
    return String(currentFacturePreviewRecord.tranche || 'Tranche 1').trim() || 'Tranche 1';
  }
  return String($('factureDocumentTypeSelect')?.value || 'Tranche 1').trim() || 'Tranche 1';
}

function getFacturePreviewStorageEntries(){
  const client = getFactureSelectedClient();
  const dossiers = Array.isArray(client?.dossiers) ? client.dossiers : [];
  if(!client) return [];
  if(currentFacturePreviewRecord && Array.isArray(currentFacturePreviewRecord.dossierIndexes)){
    return currentFacturePreviewRecord.dossierIndexes
      .map(index=>Number(index))
      .filter(index=>Number.isInteger(index) && index >= 0 && index < dossiers.length)
      .map(index=>({ client, dossier: dossiers[index], dossierIndex: index }));
  }
  const selectedEntries = getFactureSelectedDossierEntries();
  if(selectedEntries.length) return selectedEntries;
  const fallback = getFactureSelectedDossier();
  return fallback.client && fallback.dossier ? [fallback] : [];
}

function getFacturePreviewRecordSavedPayload(tranche = getFacturePreviewCurrentTranche()){
  const record = currentFacturePreviewRecord && typeof currentFacturePreviewRecord === 'object'
    ? currentFacturePreviewRecord
    : null;
  if(!record) return null;
  const normalizedTranche = String(tranche || record.tranche || 'Tranche 1').trim() || 'Tranche 1';
  const candidates = [];
  const direct = record.previewEdit && typeof record.previewEdit === 'object' ? record.previewEdit : null;
  if(direct && typeof direct.html === 'string' && direct.html.trim()){
    candidates.push(direct);
  }
  const directHtml = String(record.previewHtml || record.savedPreviewHtml || '').trim();
  if(directHtml){
    candidates.push({
      html: directHtml,
      scrollLeft: Math.max(0, Number(record.previewScrollLeft) || 0),
      scrollTop: Math.max(0, Number(record.previewScrollTop) || 0),
      updatedAt: String(record.previewUpdatedAt || record.updatedAt || '').trim()
    });
  }
  const edits = record.previewEdits && typeof record.previewEdits === 'object' ? record.previewEdits : null;
  const saved = edits ? edits[normalizedTranche] : null;
  if(typeof saved === 'string' && saved.trim()) candidates.push({ html: saved, scrollLeft: 0, scrollTop: 0 });
  if(saved && typeof saved === 'object' && typeof saved.html === 'string' && saved.html.trim()){
    candidates.push(saved);
  }
  return getNewestFacturePreviewSavedPayload(candidates);
}

function normalizeFacturePreviewSavedPayload(saved){
  if(typeof saved === 'string' && saved.trim()){
    return { html: saved, scrollLeft: 0, scrollTop: 0 };
  }
  if(saved && typeof saved === 'object' && typeof saved.html === 'string' && saved.html.trim()){
    return saved;
  }
  return null;
}

function getFacturePreviewPayloadTimestamp(payload){
  const time = payload?.updatedAt ? new Date(payload.updatedAt).getTime() : 0;
  return Number.isFinite(time) ? time : 0;
}

function getNewestFacturePreviewSavedPayload(payloads){
  const candidates = (Array.isArray(payloads) ? payloads : [])
    .map(normalizeFacturePreviewSavedPayload)
    .filter(Boolean);
  if(!candidates.length) return null;
  return candidates.slice().sort((a, b)=>getFacturePreviewPayloadTimestamp(b) - getFacturePreviewPayloadTimestamp(a))[0] || null;
}

function getFacturePreviewDossierSavedPayload(tranche){
  const normalizedTranche = String(tranche || 'Tranche 1').trim() || 'Tranche 1';
  const entries = getFacturePreviewStorageEntries();
  const dossierEditKeys = getFacturePreviewDossierEditKeys(normalizedTranche);
  for(const entry of entries){
    const edits = entry.dossier?.facturePreviewEdits;
    if(!edits || typeof edits !== 'object') continue;
    for(const editKey of dossierEditKeys){
      const savedPayload = normalizeFacturePreviewSavedPayload(edits[editKey]);
      if(savedPayload) return savedPayload;
    }
  }
  return null;
}

function getFacturePreviewSavedSnapshot(tranche){
  const normalizedTranche = String(tranche || 'Tranche 1').trim() || 'Tranche 1';
  const invoiceStorageKey = getFacturePreviewInvoiceLocalStorageKey(normalizedTranche);
  const invoiceLocalSaved = getFacturePreviewSavedPayload(invoiceStorageKey);
  const recordSaved = getFacturePreviewRecordSavedPayload(normalizedTranche);
  const storageKey = facturePreviewActiveEditKey || getFacturePreviewEditStorageKey(normalizedTranche);
  const localSaved = getFacturePreviewSavedPayload(storageKey);
  const dossierSaved = getFacturePreviewDossierSavedPayload(normalizedTranche);
  return getNewestFacturePreviewSavedPayload([invoiceLocalSaved, recordSaved, localSaved, dossierSaved]);
}

function getSavedFacturePreviewHtml(tranche){
  const savedPayload = getFacturePreviewSavedSnapshot(tranche);
  if(savedPayload?.html) return savedPayload.html;
  return '';
}

function getFacturePreviewScrollContainer(){
  return $('factureDocumentPreviewContent')?.closest?.('.facture-document-preview-body') || $('factureDocumentPreviewContent') || null;
}

function getFacturePreviewScrollTargets(){
  const content = $('factureDocumentPreviewContent');
  const body = content?.closest?.('.facture-document-preview-body') || null;
  return [body, content].filter(Boolean);
}

function getFacturePreviewScrollSnapshot(){
  const targets = getFacturePreviewScrollTargets();
  return targets.reduce((snapshot, target)=>{
    return {
      scrollLeft: Math.max(snapshot.scrollLeft, Math.max(0, Number(target.scrollLeft) || 0)),
      scrollTop: Math.max(snapshot.scrollTop, Math.max(0, Number(target.scrollTop) || 0))
    };
  }, { scrollLeft: 0, scrollTop: 0 });
}

function hasFacturePreviewWideTable(){
  const content = $('factureDocumentPreviewContent');
  const tables = [...(content?.querySelectorAll?.('table') || [])];
  return tables.some((table)=>{
    const maxCols = [...(table.rows || [])].reduce((max, row)=>{
      const count = [...row.cells].reduce((sum, cell)=>sum + Math.max(1, Number(cell.colSpan) || 1), 0);
      return Math.max(max, count);
    }, 0);
    return maxCols > 7;
  });
}

function fitFacturePreviewSheetToSavedColumns(){
  const content = $('factureDocumentPreviewContent');
  const sheet = content?.querySelector?.('.facture-sheet-pro');
  const table = sheet?.querySelector?.('.facture-pro-table, .facture-sheet-lines, table');
  if(!sheet || !table) return;
  const colgroupCols = [...(table.querySelectorAll?.('colgroup col') || [])];
  const maxCols = [...(table.rows || [])].reduce((max, row)=>{
    const count = [...row.cells].reduce((sum, cell)=>sum + Math.max(1, Number(cell.colSpan) || 1), 0);
    return Math.max(max, count);
  }, colgroupCols.length);
  if(maxCols <= 0) return;
  const estimatedTableWidth = colgroupCols.reduce((sum, col)=>{
    const explicitWidth = Number.parseFloat(String(col.style?.width || '').replace('px', ''));
    if(Number.isFinite(explicitWidth) && explicitWidth > 0) return sum + explicitWidth;
    return sum + 145;
  }, 0) || (maxCols * 145);
  const nextSheetWidth = Math.max(Number.parseFloat(getComputedStyle(sheet).width) || 0, estimatedTableWidth + 56);
  if(nextSheetWidth > 0){
    sheet.style.width = `${Math.ceil(nextSheetWidth)}px`;
    sheet.style.maxWidth = 'none';
    table.style.width = 'max-content';
    table.style.minWidth = '100%';
  }
}

function getFacturePreviewSavedPayload(storageKey){
  const key = String(storageKey || '').trim();
  if(!key) return null;
  const edits = readLocalFacturePreviewEdits();
  return normalizeFacturePreviewSavedPayload(edits[key]);
}

function restoreFacturePreviewScroll(savedPayload = null){
  const safeLeft = Math.max(0, Number(savedPayload?.scrollLeft) || 0);
  const safeTop = Math.max(0, Number(savedPayload?.scrollTop) || 0);
  const applyScroll = ()=>{
    const targets = getFacturePreviewScrollTargets();
    const shouldShowRightSide = !!savedPayload?.html && hasFacturePreviewWideTable();
    targets.forEach((target)=>{
      if(!target) return;
      const maxLeft = Math.max(0, Number(target.scrollWidth || 0) - Number(target.clientWidth || 0));
      const nextLeft = shouldShowRightSide ? maxLeft : (safeLeft || (savedPayload?.html ? maxLeft : 0));
      target.scrollLeft = Math.min(maxLeft, Math.max(0, nextLeft));
      target.scrollTop = safeTop;
    });
  };
  requestAnimationFrame(applyScroll);
  setTimeout(applyScroll, 60);
  setTimeout(applyScroll, 180);
}

function applyFacturePreviewSavedSnapshot(html, savedPayload = null){
  const content = $('factureDocumentPreviewContent');
  if(!content) return false;
  const safeHtml = String(html || '').trim();
  if(!safeHtml) return false;
  content.innerHTML = safeHtml;
  fitFacturePreviewSheetToSavedColumns();
  facturePreviewEdited = true;
  content.classList.add('is-edited');
  setFacturePreviewEditMode(false);
  restoreFacturePreviewScroll(savedPayload || { html: safeHtml });
  return true;
}

function getFacturePreviewEditStorageKey(tranche = getFacturePreviewCurrentTranche()){
  const client = getFactureSelectedClient();
  const entries = getFacturePreviewStorageEntries();
  const dossierPart = entries
    .map(entry=>Number(entry.dossierIndex))
    .filter(index=>Number.isInteger(index))
    .sort((a, b)=>a - b)
    .join('-');
  const recordPart = currentFacturePreviewRecord?.id ? `record-${currentFacturePreviewRecord.id}` : '';
  return [
    String(client?.id || selectedFactureClientId || '').trim(),
    recordPart || dossierPart || 'dossier',
    String(tranche || 'Tranche 1').trim() || 'Tranche 1'
  ].join('|');
}

function getFacturePreviewInvoiceLocalStorageKey(tranche = getFacturePreviewCurrentTranche()){
  const client = getFactureSelectedClient();
  const recordId = String(currentFacturePreviewRecord?.id || '').trim();
  if(!recordId) return '';
  return [
    String(client?.id || selectedFactureClientId || '').trim(),
    `invoice-${recordId}`,
    String(tranche || currentFacturePreviewRecord?.tranche || 'Tranche 1').trim() || 'Tranche 1'
  ].join('|');
}

function getFacturePreviewDossierEditKeys(tranche = getFacturePreviewCurrentTranche()){
  const normalizedTranche = String(tranche || 'Tranche 1').trim() || 'Tranche 1';
  const recordId = String(currentFacturePreviewRecord?.id || '').trim();
  if(recordId) return [`record:${recordId}:${normalizedTranche}`];
  return [normalizedTranche];
}

function readLocalFacturePreviewEdits(){
  try{
    const raw = localStorage.getItem(FACTURE_PREVIEW_EDITS_STORAGE_KEY);
    const parsed = raw ? JSON.parse(raw) : {};
    return parsed && typeof parsed === 'object' ? parsed : {};
  }catch(err){
    console.warn('Impossible de lire les modifications facture locales', err);
    return {};
  }
}

function getLocalFacturePreviewEdit(storageKey){
  return getFacturePreviewSavedPayload(storageKey)?.html || '';
}

function saveLocalFacturePreviewEdit(storageKey, html){
  const key = String(storageKey || '').trim();
  const safeHtml = String(html || '').trim();
  if(!key || !safeHtml) return;
  try{
    const edits = readLocalFacturePreviewEdits();
    const scrollSnapshot = getFacturePreviewScrollSnapshot();
    edits[key] = {
      html: safeHtml,
      scrollLeft: scrollSnapshot.scrollLeft,
      scrollTop: scrollSnapshot.scrollTop,
      updatedAt: new Date().toISOString()
    };
    localStorage.setItem(FACTURE_PREVIEW_EDITS_STORAGE_KEY, JSON.stringify(edits));
  }catch(err){
    console.warn('Impossible de sauvegarder les modifications facture locales', err);
  }
}

function queueFacturePreviewLocalAutosave(delayMs = 250){
  if(facturePreviewAutosaveTimer){
    clearTimeout(facturePreviewAutosaveTimer);
    facturePreviewAutosaveTimer = null;
  }
  facturePreviewAutosaveTimer = setTimeout(()=>{
    facturePreviewAutosaveTimer = null;
    const content = $('factureDocumentPreviewContent');
    const html = String(content?.innerHTML || '').trim();
    if(!content || !html) return;
    const tranche = getFacturePreviewCurrentTranche();
    const storageKey = facturePreviewActiveEditKey || getFacturePreviewEditStorageKey(tranche);
    facturePreviewActiveEditKey = storageKey;
    saveLocalFacturePreviewEdit(storageKey, html);
    saveLocalFacturePreviewEdit(getFacturePreviewInvoiceLocalStorageKey(tranche), html);
  }, Math.max(0, Number(delayMs) || 0));
}

function attachFacturePreviewEditableNodeHandlers(node){
  if(!node) return;
  node.contentEditable = facturePreviewEditMode ? 'true' : 'false';
  node.spellcheck = false;
  node.onfocus = ()=>{
    if(node.matches?.('td, th')) facturePreviewLastFocusedCell = node;
  };
  node.onpointerdown = ()=>{
    if(node.matches?.('td, th')) facturePreviewLastFocusedCell = node;
  };
  node.oninput = ()=>{
    markFacturePreviewEdited();
    queueFacturePreviewLocalAutosave();
  };
}

async function saveFacturePreviewEdits(){
  if(!facturePreviewEdited) return false;
  if(!canEditData()) return alert('Acces refuse');
  const content = $('factureDocumentPreviewContent');
  const html = String(content?.innerHTML || '').trim();
  if(!content || !html) return false;
  const tranche = getFacturePreviewCurrentTranche();
  const entries = getFacturePreviewStorageEntries();
  const storageKey = facturePreviewActiveEditKey || getFacturePreviewEditStorageKey(tranche);
  facturePreviewActiveEditKey = storageKey;
  const scrollSnapshot = getFacturePreviewScrollSnapshot();
  const previewPayload = {
    html,
    scrollLeft: scrollSnapshot.scrollLeft,
    scrollTop: scrollSnapshot.scrollTop,
    updatedAt: new Date().toISOString()
  };
  if(facturePreviewAutosaveTimer){
    clearTimeout(facturePreviewAutosaveTimer);
    facturePreviewAutosaveTimer = null;
  }
  saveLocalFacturePreviewEdit(storageKey, html);
  saveLocalFacturePreviewEdit(getFacturePreviewInvoiceLocalStorageKey(tranche), html);
  if(currentFacturePreviewRecord && typeof currentFacturePreviewRecord === 'object'){
    currentFacturePreviewRecord.previewHtml = html;
    currentFacturePreviewRecord.savedPreviewHtml = html;
    currentFacturePreviewRecord.previewScrollLeft = scrollSnapshot.scrollLeft;
    currentFacturePreviewRecord.previewScrollTop = scrollSnapshot.scrollTop;
    currentFacturePreviewRecord.previewUpdatedAt = previewPayload.updatedAt;
    currentFacturePreviewRecord.previewEdit = previewPayload;
    currentFacturePreviewRecord.previewEdits = {
      ...(currentFacturePreviewRecord.previewEdits && typeof currentFacturePreviewRecord.previewEdits === 'object'
        ? currentFacturePreviewRecord.previewEdits
        : {}),
      [tranche]: previewPayload
    };
  }
  if(!entries.length) return true;
  entries.forEach(entry=>{
    const targetDossier = entry.dossier;
    if(!targetDossier || typeof targetDossier !== 'object') return;
    const edits = targetDossier.facturePreviewEdits && typeof targetDossier.facturePreviewEdits === 'object'
      ? { ...targetDossier.facturePreviewEdits }
      : {};
    getFacturePreviewDossierEditKeys(tranche).forEach((editKey)=>{
      edits[editKey || tranche] = previewPayload;
    });
    targetDossier.facturePreviewEdits = edits;
    if(currentFacturePreviewRecord?.id && Array.isArray(targetDossier.factureInvoices)){
      targetDossier.factureInvoices = targetDossier.factureInvoices.map((rawRecord)=>{
        const record = normalizeFactureTrackingRecord(rawRecord);
        if(!record || record.id !== currentFacturePreviewRecord.id) return rawRecord;
        return {
          ...rawRecord,
          previewHtml: html,
          savedPreviewHtml: html,
          previewScrollLeft: scrollSnapshot.scrollLeft,
          previewScrollTop: scrollSnapshot.scrollTop,
          previewUpdatedAt: previewPayload.updatedAt,
          previewEdit: previewPayload,
          previewEdits: {
            ...(rawRecord?.previewEdits && typeof rawRecord.previewEdits === 'object' ? rawRecord.previewEdits : {}),
            [tranche]: previewPayload
          }
        };
      });
    }
  });
  handleDossierDataChange({ audience: false });
  for(const entry of entries){
    await persistDossierPatchNow({
      action: 'update',
      clientId: Number(entry.client.id),
      dossierIndex: Number(entry.dossierIndex),
      dossier: entry.dossier
    }, { source: 'facture-preview-edit' });
  }
  return true;
}

async function handleFacturePreviewSaveClick(){
  const btn = $('saveFacturePreviewEditsBtn');
  const originalHtml = btn?.innerHTML || '<i class="fa-solid fa-floppy-disk"></i> Sauvegarder';
  if(btn){
    btn.disabled = true;
    btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Sauvegarde...';
  }
  try{
    if(!facturePreviewEdited){
      markFacturePreviewEdited();
    }
    const saved = await saveFacturePreviewEdits();
    if(btn){
      btn.innerHTML = saved
        ? '<i class="fa-solid fa-check"></i> Sauvegardee'
        : '<i class="fa-solid fa-check"></i> Deja sauvegardee';
      setTimeout(()=>{
        btn.disabled = false;
        btn.innerHTML = originalHtml;
      }, 1200);
    }
  }catch(err){
    console.error(err);
    if(btn){
      btn.disabled = false;
      btn.innerHTML = originalHtml;
    }
    alert('Erreur pendant la sauvegarde facture');
  }
}

function setFacturePreviewEditMode(enabled){
  facturePreviewEditMode = !!enabled;
  const content = $('factureDocumentPreviewContent');
  const toggleBtn = $('toggleFacturePreviewEditBtn');
  const rowBtn = $('addFacturePreviewRowBtn');
  const colBtn = $('addFacturePreviewColumnBtn');
  if(content) content.classList.toggle('is-editing', facturePreviewEditMode);
  getFacturePreviewEditableNodes().forEach(node=>{
    attachFacturePreviewEditableNodeHandlers(node);
  });
  if(toggleBtn){
    toggleBtn.innerHTML = facturePreviewEditMode
      ? '<i class="fa-solid fa-check"></i> Terminer'
      : '<i class="fa-solid fa-pen-to-square"></i> Modifier';
  }
  if(rowBtn) rowBtn.disabled = !facturePreviewEditMode;
  if(colBtn) colBtn.disabled = !facturePreviewEditMode;
}

async function toggleFacturePreviewEditMode(){
  if(facturePreviewEditMode){
    await saveFacturePreviewEdits();
  }
  setFacturePreviewEditMode(!facturePreviewEditMode);
}

function getActiveFacturePreviewTable(){
  const active = document.activeElement;
  return active?.closest?.('#factureDocumentPreviewContent table')
    || $('factureDocumentPreviewContent')?.querySelector('.facture-pro-table, .facture-sheet-lines, table')
    || null;
}

function addFacturePreviewRow(){
  if(!facturePreviewEditMode) return;
  const table = getActiveFacturePreviewTable();
  const tbody = table?.tBodies?.[0];
  if(!tbody) return;
  const rows = [...tbody.rows].filter(row=>!row.classList.contains('facture-pro-total-row') && !row.classList.contains('facture-total-row') && !row.classList.contains('facture-ttc-row'));
  const sourceRow = rows[rows.length - 1] || tbody.rows[tbody.rows.length - 1];
  if(!sourceRow) return;
  const nextRow = sourceRow.cloneNode(true);
  [...nextRow.cells].forEach(cell=>{
    cell.textContent = '';
    cell.contentEditable = 'true';
    cell.spellcheck = false;
  });
  const totalRow = [...tbody.rows].find(row=>row.classList.contains('facture-pro-total-row') || row.classList.contains('facture-total-row'));
  tbody.insertBefore(nextRow, totalRow || null);
  [...nextRow.querySelectorAll('td, th, div')].forEach(attachFacturePreviewEditableNodeHandlers);
  markFacturePreviewEdited();
  queueFacturePreviewLocalAutosave(0);
}

function addFacturePreviewColumn(){
  if(!facturePreviewEditMode) return;
  const table = getActiveFacturePreviewTable();
  if(!table) return;
  const insertColumnIndex = getFacturePreviewLastVisualColumnIndex(table) + 1;
  insertFacturePreviewColGroupColumn(table, insertColumnIndex);
  let firstInsertedCell = null;
  [...table.rows].forEach(row=>{
    const insertedCell = insertFacturePreviewCellAtVisualIndex(row, insertColumnIndex);
    if(!firstInsertedCell && insertedCell) firstInsertedCell = insertedCell;
  });
  markFacturePreviewEdited();
  setFacturePreviewEditMode(true);
  if(firstInsertedCell){
    facturePreviewLastFocusedCell = firstInsertedCell;
    firstInsertedCell.focus();
    firstInsertedCell.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'end' });
  }
  setTimeout(()=>queueFacturePreviewLocalAutosave(0), 180);
}

function getFacturePreviewVisualColumnIndex(cell){
  if(!cell) return -1;
  let index = 0;
  let node = cell;
  while(node.previousElementSibling){
    node = node.previousElementSibling;
    index += Math.max(1, Number(node.colSpan) || 1);
  }
  return index;
}

function getFacturePreviewLastVisualColumnIndex(table){
  const rows = [...(table?.rows || [])];
  const maxCount = rows.reduce((max, row)=>{
    const count = [...row.cells].reduce((sum, cell)=>sum + Math.max(1, Number(cell.colSpan) || 1), 0);
    return Math.max(max, count);
  }, 0);
  return Math.max(0, maxCount - 1);
}

function insertFacturePreviewColGroupColumn(table, visualIndex){
  const colgroup = table?.querySelector?.('colgroup');
  if(!colgroup) return;
  const cols = [...colgroup.children].filter(child=>child.tagName === 'COL');
  const sourceCol = cols[Math.max(0, Math.min(visualIndex - 1, cols.length - 1))];
  const nextCol = sourceCol ? sourceCol.cloneNode(false) : document.createElement('col');
  if(sourceCol?.className){
    nextCol.className = sourceCol.className;
  }
  colgroup.insertBefore(nextCol, cols[visualIndex] || null);
}

function insertFacturePreviewCellAtVisualIndex(row, visualIndex){
  if(!row) return null;
  let cursor = 0;
  const cells = [...row.cells];
  for(let index = 0; index < cells.length; index += 1){
    const cell = cells[index];
    const span = Math.max(1, Number(cell.colSpan) || 1);
    if(visualIndex > cursor && visualIndex < cursor + span){
      cell.colSpan = span + 1;
      return null;
    }
    if(visualIndex === cursor){
      const nextCell = cloneFacturePreviewInsertCell(row, cells[index - 1] || cell);
      row.insertBefore(nextCell, cell);
      return nextCell;
    }
    cursor += span;
  }
  const nextCell = cloneFacturePreviewInsertCell(row, cells[cells.length - 1]);
  row.appendChild(nextCell);
  return nextCell;
}

function cloneFacturePreviewInsertCell(row, sourceCell){
  const tagName = row.parentElement?.tagName === 'THEAD' ? 'th' : 'td';
  const nextCell = sourceCell ? sourceCell.cloneNode(true) : document.createElement(tagName);
  nextCell.removeAttribute('colspan');
  nextCell.removeAttribute('rowspan');
  nextCell.textContent = '';
  nextCell.contentEditable = 'true';
  nextCell.spellcheck = false;
  return nextCell;
}

function getFactureDocumentAmount(value){
  const text = String(value || '').replace(/\s+/g, ' ');
  const match = text.match(/(\d[\d\s.,]*\d|\d+)/);
  if(!match) return '';
  return match[1].replace(/\s+/g, '').replace(',', '.');
}

function findFactureProcedureDetails(dossier, procedureName){
  const details = dossier?.procedureDetails && typeof dossier.procedureDetails === 'object'
    ? dossier.procedureDetails
    : {};
  const wanted = normalizeProcedureName(String(procedureName || '').trim());
  if(!wanted) return null;
  if(details[procedureName] && typeof details[procedureName] === 'object') return details[procedureName];
  const matchedKey = Object.keys(details).find(key=>normalizeProcedureName(key) === wanted);
  return matchedKey && typeof details[matchedKey] === 'object' ? details[matchedKey] : null;
}

function getFactureSelectedProcedure(dossier){
  const procedures = getFactureDossierProcedures(dossier);
  const selected = String(selectedFactureProcedure || '').trim();
  if(selected && procedures.some(proc=>normalizeProcedureName(proc) === normalizeProcedureName(selected))){
    return selected;
  }
  return procedures[0] || String(dossier?.procedure || '').split(',').map(value=>value.trim()).filter(Boolean)[0] || '';
}

function getFactureProcedureChoiceForDossier(dossier, dossierIndex){
  const selected = String(selectedFactureProceduresByDossier.get(Number(dossierIndex)) || '').trim();
  const procedures = getFactureDossierProcedures(dossier);
  if(selected && procedures.some(proc=>normalizeProcedureName(proc) === normalizeProcedureName(selected))){
    return selected;
  }
  return procedures[0] || String(dossier?.procedure || '').split(',').map(value=>value.trim()).filter(Boolean)[0] || '';
}

function getFactureProcedureReference(dossier, procedureName, dossierIndex = selectedFactureDossierIndex){
  const details = findFactureProcedureDetails(dossier, procedureName);
  return String(
    details?.referenceClient
    || dossier?.referenceClient
    || dossier?.nRef
    || `Dossier ${Number(dossierIndex) + 1}`
  ).trim();
}

function getFactureProcedureAmountText(dossier, procedureName){
  const wanted = normalizeProcedureName(String(procedureName || '').trim());
  const groups = Array.isArray(dossier?.montantByProcedure) ? dossier.montantByProcedure : [];
  const matchedGroup = groups.find(group=>
    Array.isArray(group?.procedures)
    && group.procedures.some(proc=>normalizeProcedureName(proc) === wanted)
    && String(group?.montant || '').trim()
  );
  return String(matchedGroup?.montant || dossier?.montant || '').trim();
}

function getFactureProcesVerbalLineEntries(){
  const selectedEntries = getFactureSelectedDossierEntries();
  const fallback = getFactureSelectedDossier();
  const targetEntries = selectedEntries.length ? selectedEntries : (
    fallback.client && fallback.dossier ? [fallback] : []
  );
  return targetEntries.map(entry=>{
    const procedure = getFactureProcedureChoiceForDossier(entry.dossier, entry.dossierIndex);
    const procedureDetails = findFactureProcedureDetails(entry.dossier, procedure) || {};
    const reference = getFactureProcedureReference(entry.dossier, procedure, entry.dossierIndex);
    const amountText = getFactureProcedureAmountText(entry.dossier, procedure) || '0';
    const amount = Number(String(amountText).replace(/\s+/g, '').replace(',', '.')) || 0;
    const taxe = amount;
    const vignette = 0;
    const med = 0;
    const fraisTimbrage = 0;
    const huissierAudience = suppressAudienceFactureHuissier ? '' : 200;
    const deplacement = 0;
    return {
      client: entry.client,
      dossier: entry.dossier,
      dossierIndex: entry.dossierIndex,
      type: entry.dossier?.type || '-',
      refClient: entry.dossier?.referenceClient || entry.dossier?.nRef || '-',
      nom: entry.dossier?.debiteur || '-',
      procedure,
      reference,
      stade: procedureDetails.stade || 'JUG',
      dateDepot: procedureDetails.depotLe || procedureDetails.dateDepot || '',
      dateJugement: procedureDetails.audience || '',
      jugementNo: procedureDetails.jugementNo || '',
      tribunal: procedureDetails.tribunal || '',
      amount,
      taxe,
      vignette,
      med,
      fraisTimbrage,
      huissierAudience,
      deplacement,
      frais: vignette + med + fraisTimbrage + huissierAudience + deplacement,
      debiteur: entry.dossier?.debiteur || '-',
      ville: entry.dossier?.ville || '',
      designation: `Proces-verbal ${procedure || ''}${reference ? ` - Ref ${reference}` : ''}`.trim()
    };
  }).filter(line=>line.dossier);
}

function buildFactureInvoiceKey(lines, tranche){
  const clientId = String(lines?.[0]?.client?.id || selectedFactureClientId || '').trim();
  const parts = (Array.isArray(lines) ? lines : []).map(line=>[
    line.dossierIndex,
    line.refClient,
    line.procedure,
    line.reference
  ].map(value=>String(value || '').trim()).join(':'));
  return [clientId, tranche, ...parts].join('|');
}

function generateFactureInvoiceNumber(lines, tranche){
  const year = new Date().getFullYear();
  const key = buildFactureInvoiceKey(lines, tranche);
  if(currentFactureInvoiceKey === key && currentFactureInvoiceNumber){
    return currentFactureInvoiceNumber;
  }
  const storageKey = `cabinet-facture-invoice-seq-${year}`;
  let nextNumber = 1;
  try{
    const previous = Number(localStorage.getItem(storageKey) || '0') || 0;
    nextNumber = previous + 1;
    localStorage.setItem(storageKey, String(nextNumber));
  }catch(err){
    nextNumber = Math.max(1, Number(String(Date.now()).slice(-4)) || 1);
  }
  currentFactureInvoiceKey = key;
  currentFactureInvoiceNumber = `${nextNumber}/${year}`;
  return currentFactureInvoiceNumber;
}

function formatFactureMoney(value){
  return Number(value || 0).toLocaleString('fr-FR', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  });
}

function hashFactureTrackingValue(value){
  const text = String(value || '');
  let hash = 2166136261;
  for(let index = 0; index < text.length; index += 1){
    hash ^= text.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(36);
}

function buildFactureTrackingRecord(data, tranche){
  const lines = Array.isArray(data?.lines) ? data.lines : [];
  const normalizedTranche = String(tranche || 'Tranche 1').trim() || 'Tranche 1';
  const invoiceRef = String(data?.invoiceRef || '').trim();
  const signature = [
    data?.client?.id || selectedFactureClientId || '',
    normalizedTranche,
    invoiceRef,
    ...lines.map(line=>[
      line.dossierIndex,
      line.refClient,
      line.nom,
      line.procedure,
      line.reference
    ].map(value=>String(value || '').trim()).join(':'))
  ].join('|');
  return {
    id: `facture-${hashFactureTrackingValue(signature || `${Date.now()}`)}`,
    invoiceRef,
    tranche: normalizedTranche,
    amount: Number(data?.amount) || 0,
    totalTtc: Number(data?.totalTtc) || Number(data?.amount) || 0,
    clientName: String(data?.clientName || '').trim(),
    objet: String(data?.objet || '').trim(),
    createdAt: new Date().toISOString(),
    status: 'unpaid',
    paidAt: '',
    lines: lines.map(line=>({
      dossierIndex: Number(line.dossierIndex),
      type: String(line.type || '').trim(),
      refClient: String(line.refClient || '').trim(),
      nom: String(line.nom || '').trim(),
      procedure: String(line.procedure || '').trim(),
      reference: String(line.reference || '').trim(),
      ville: String(line.ville || '').trim(),
      stade: String(line.stade || '').trim(),
      dateDepot: String(line.dateDepot || '').trim(),
      dateJugement: String(line.dateJugement || '').trim(),
      jugementNo: String(line.jugementNo || '').trim(),
      tribunal: String(line.tribunal || '').trim(),
      amount: Number(line.amount) || 0
    }))
  };
}

function normalizeFactureTrackingRecord(record){
  if(!record || typeof record !== 'object') return null;
  const id = String(record.id || '').trim();
  if(!id) return null;
  return {
    ...record,
    id,
    invoiceRef: String(record.invoiceRef || '').trim(),
    tranche: String(record.tranche || 'Tranche 1').trim() || 'Tranche 1',
    amount: Number(record.amount) || 0,
    totalTtc: Number(record.totalTtc) || Number(record.amount) || 0,
    createdAt: String(record.createdAt || '').trim(),
    status: String(record.status || '').trim() === 'paid' ? 'paid' : 'unpaid',
    paidAt: String(record.paidAt || '').trim(),
    lines: Array.isArray(record.lines) ? record.lines : []
  };
}

function renderCreationFactureStatus(dossier = null){
  const card = $('creationFactureStatusCard');
  const count = $('creationFactureStatusCount');
  const list = $('creationFactureStatusList');
  if(!card || !list) return;
  const records = Array.isArray(dossier?.factureInvoices)
    ? dossier.factureInvoices.map(normalizeFactureTrackingRecord).filter(Boolean)
    : [];
  if(!records.length){
    card.style.display = 'none';
    list.innerHTML = '';
    if(count) count.textContent = '0 facture';
    return;
  }
  card.style.display = '';
  if(count) count.textContent = `${records.length} facture${records.length > 1 ? 's' : ''}`;
  list.innerHTML = records
    .slice()
    .sort((a, b)=>String(b.createdAt || '').localeCompare(String(a.createdAt || '')))
    .map(record=>{
      const paid = record.status === 'paid';
      const amount = /^Tranche\s*[14]$/i.test(record.tranche) ? record.amount : record.totalTtc;
      return `
        <div class="creation-facture-status-item ${paid ? 'is-paid' : 'is-unpaid'}">
          <div class="creation-facture-status-main">
            <strong>${escapeHtml(record.tranche || 'Tranche')}</strong>
            <span>Facture ${escapeHtml(record.invoiceRef || '-')}</span>
            <small>${escapeHtml(formatFactureTrackingDate(record.createdAt))} · ${escapeHtml(formatFactureMoney(amount))}</small>
          </div>
          <span class="creation-facture-status-badge ${paid ? 'is-paid' : 'is-unpaid'}">
            ${paid ? 'Payee' : 'Non payee'}
          </span>
        </div>
      `;
    }).join('');
}

function getFactureTrackingRecordById(invoiceId){
  const id = String(invoiceId || '').trim();
  if(!id) return null;
  return collectFactureTrackingRecords().find(record=>record.id === id) || null;
}

function buildFactureDataFromTrackingRecord(record){
  const normalized = normalizeFactureTrackingRecord(record);
  if(!normalized) return null;
  const client = getFactureSelectedClient();
  const lines = normalized.lines.map((line, index)=>{
    const amount = Number(line.amount) || 0;
    return {
      client,
      dossier: null,
      dossierIndex: Number.isInteger(Number(line.dossierIndex)) ? Number(line.dossierIndex) : index,
      type: String(line.type || '-').trim() || '-',
      refClient: String(line.refClient || '-').trim() || '-',
      nom: String(line.nom || '-').trim() || '-',
      procedure: String(line.procedure || '').trim(),
      reference: String(line.reference || '').trim(),
      stade: String(line.stade || 'JUG').trim() || 'JUG',
      dateDepot: String(line.dateDepot || '').trim(),
      dateJugement: String(line.dateJugement || '').trim(),
      jugementNo: String(line.jugementNo || '').trim(),
      tribunal: String(line.tribunal || '').trim(),
      amount,
      taxe: amount,
      vignette: 0,
      med: 0,
      fraisTimbrage: 0,
      huissierAudience: /^Tranche\s*1$/i.test(normalized.tranche) ? 200 : 0,
      deplacement: 0,
      frais: /^Tranche\s*1$/i.test(normalized.tranche) ? 200 : 0,
      debiteur: String(line.nom || '').trim(),
      ville: String(line.ville || '').trim(),
      designation: `Facture ${normalized.tranche}${line.reference ? ` - Ref ${line.reference}` : ''}`.trim()
    };
  });
  const amount = Number(normalized.amount) || lines.reduce((sum, line)=>sum + (Number(line.amount) || 0), 0);
  const tva = /^Tranche\s*[23]$/i.test(normalized.tranche)
    ? Math.max(0, Number(normalized.totalTtc || 0) - amount) || amount * 0.2
    : amount * 0.2;
  const totalTtc = Number(normalized.totalTtc) || amount + tva;
  const taxeTotal = lines.reduce((sum, line)=>sum + (Number(line.taxe) || 0), 0);
  const huissierAudienceTotal = lines.reduce((sum, line)=>sum + (Number(line.huissierAudience) || 0), 0);
  const date = normalized.createdAt ? new Date(normalized.createdAt) : new Date();
  const today = date && !Number.isNaN(date.getTime())
    ? (typeof formatDateDDMMYYYY === 'function' ? formatDateDDMMYYYY(date) : date.toLocaleDateString('fr-FR'))
    : (typeof formatDateDDMMYYYY === 'function' ? formatDateDDMMYYYY(new Date()) : new Date().toLocaleDateString('fr-FR'));
  return {
    client,
    dossier: null,
    lines,
    tranches: '',
    tranche: normalized.tranche,
    amount,
    taxeTotal,
    vignetteTotal: 0,
    medTotal: 0,
    fraisTimbrageTotal: 0,
    huissierAudienceTotal,
    deplacementTotal: 0,
    fraisTotal: huissierAudienceTotal,
    netAPayer: taxeTotal + huissierAudienceTotal,
    tva,
    totalTtc,
    invoiceRef: normalized.invoiceRef,
    today,
    clientName: normalized.clientName || client?.name || '-',
    debiteur: lines.map(line=>line.nom).filter(Boolean).join(' | ') || '-',
    objet: normalized.objet || lines.map(line=>`${line.procedure || 'Procedure'}${line.reference ? ` (${line.reference})` : ''}`).join(' | '),
    selectedProcedure: lines[0]?.procedure || ''
  };
}

function upsertFactureTrackingRecord(dossier, record){
  if(!dossier || typeof dossier !== 'object' || !record?.id) return false;
  const records = Array.isArray(dossier.factureInvoices)
    ? dossier.factureInvoices.map(normalizeFactureTrackingRecord).filter(Boolean)
    : [];
  const existingIndex = records.findIndex(item=>String(item.id || '') === String(record.id || ''));
  if(existingIndex === -1){
    dossier.factureInvoices = [record, ...records];
    return true;
  }
  const existing = records[existingIndex];
  records[existingIndex] = {
    ...existing,
    ...record,
    status: existing.status || record.status || 'unpaid',
    paidAt: existing.paidAt || record.paidAt || '',
    createdAt: existing.createdAt || record.createdAt || new Date().toISOString()
  };
  dossier.factureInvoices = records;
  return true;
}

function collectFactureTrackingRecords(client = getFactureSelectedClient()){
  const dossiers = Array.isArray(client?.dossiers) ? client.dossiers : [];
  const byId = new Map();
  dossiers.forEach((dossier, dossierIndex)=>{
    const records = Array.isArray(dossier?.factureInvoices) ? dossier.factureInvoices : [];
    records.forEach(rawRecord=>{
      const record = normalizeFactureTrackingRecord(rawRecord);
      if(!record) return;
      const existing = byId.get(record.id) || {
        ...record,
        dossierIndexes: new Set(),
        dossierLabels: new Set()
      };
      existing.status = existing.status === 'paid' || record.status === 'paid' ? 'paid' : 'unpaid';
      existing.paidAt = existing.paidAt || record.paidAt || '';
      existing.amount = Number(existing.amount || record.amount) || 0;
      existing.totalTtc = Number(existing.totalTtc || record.totalTtc) || 0;
      if(!existing.previewEdit && record.previewEdit){
        existing.previewEdit = record.previewEdit;
      }
      if(record.previewEdits && typeof record.previewEdits === 'object'){
        existing.previewEdits = {
          ...(existing.previewEdits && typeof existing.previewEdits === 'object' ? existing.previewEdits : {}),
          ...record.previewEdits
        };
      }
      existing.dossierIndexes.add(dossierIndex);
      existing.dossierLabels.add(String(dossier?.referenceClient || dossier?.debiteur || `Dossier ${dossierIndex + 1}`).trim());
      byId.set(record.id, existing);
    });
  });
  return [...byId.values()]
    .map(record=>({
      ...record,
      dossierIndexes: [...record.dossierIndexes],
      dossierLabels: [...record.dossierLabels].filter(Boolean)
    }))
    .sort((a, b)=>String(b.createdAt || '').localeCompare(String(a.createdAt || '')));
}

function formatFactureTrackingDate(value){
  const date = value ? new Date(value) : null;
  if(date && !Number.isNaN(date.getTime())){
    return typeof formatDateDDMMYYYY === 'function' ? formatDateDDMMYYYY(date) : date.toLocaleDateString('fr-FR');
  }
  return '-';
}

function getFactureTrackingSearchText(record){
  const normalized = normalizeFactureTrackingRecord(record);
  if(!normalized) return '';
  const paidLabel = normalized.status === 'paid' ? 'payee facture payee payer' : 'non payee facture non payee impayee';
  const lineValues = Array.isArray(normalized.lines)
    ? normalized.lines.flatMap(line=>[
        line?.refClient,
        line?.nom,
        line?.procedure,
        line?.reference,
        line?.type,
        line?.ville,
        line?.amount
      ])
    : [];
  return [
    normalized.invoiceRef,
    normalized.tranche,
    normalized.clientName,
    normalized.objet,
    normalized.amount,
    normalized.totalTtc,
    formatFactureTrackingDate(normalized.createdAt),
    paidLabel,
    ...(Array.isArray(normalized.dossierLabels) ? normalized.dossierLabels : []),
    ...lineValues
  ].map(value=>normalizeCaseInsensitiveSearchText(value)).filter(Boolean).join(' ');
}

function filterFactureTrackingRecords(records){
  const query = normalizeCaseInsensitiveSearchText($('factureTrackingSearchInput')?.value || '');
  if(!query) return records;
  const tokens = query.split(/\s+/).map(token=>token.trim()).filter(Boolean);
  if(!tokens.length) return records;
  return records.filter(record=>{
    const haystack = record.__factureTrackingSearchText || (record.__factureTrackingSearchText = getFactureTrackingSearchText(record));
    return tokens.every(token=>haystack.includes(token));
  });
}

function renderFactureTracking(){
  const list = $('factureTrackingList');
  const count = $('factureTrackingCount');
  if(!list) return;
  const client = getFactureSelectedClient();
  const records = collectFactureTrackingRecords(client);
  const filteredRecords = filterFactureTrackingRecords(records);
  if(count){
    count.textContent = filteredRecords.length === records.length
      ? `${records.length} facture${records.length > 1 ? 's' : ''}`
      : `${filteredRecords.length}/${records.length} facture${records.length > 1 ? 's' : ''}`;
  }
  if(!client){
    list.innerHTML = '<div class="facture-tracking-empty">Choisir client pour voir le suivi.</div>';
    return;
  }
  if(!records.length){
    list.innerHTML = '<div class="facture-tracking-empty">Aucune facture enregistree pour ce client.</div>';
    return;
  }
  if(!filteredRecords.length){
    list.innerHTML = '<div class="facture-tracking-empty">Aucune facture ne correspond au filtre.</div>';
    return;
  }
  list.innerHTML = filteredRecords.map(record=>{
    const paid = record.status === 'paid';
    const statusLabel = paid ? 'Payee' : 'Non payee';
    const statusClass = paid ? ' is-paid' : ' is-unpaid';
    const dossierLabels = record.dossierLabels.join(' | ') || '-';
    const amount = /^Tranche\s*[14]$/i.test(record.tranche)
      ? record.amount
      : record.totalTtc;
    return `
      <div class="facture-tracking-item${statusClass}" data-invoice-id="${escapeAttr(record.id)}">
        <div class="facture-tracking-main">
          <div class="facture-tracking-title">
            <span>${escapeHtml(record.tranche)}</span>
            <strong>Facture ${escapeHtml(record.invoiceRef || '-')}</strong>
          </div>
          <div class="facture-tracking-meta">
            <span>${escapeHtml(formatFactureTrackingDate(record.createdAt))}</span>
            <span>${escapeHtml(dossierLabels)}</span>
            <span>${escapeHtml(formatFactureMoney(amount))}</span>
          </div>
        </div>
        <div class="facture-tracking-actions">
          <button class="facture-paid-toggle${statusClass}" type="button" data-invoice-id="${escapeAttr(record.id)}" title="Double click pour changer le paiement" ${canEditData() ? '' : 'disabled'}>
            <i class="fa-solid ${paid ? 'fa-circle-check' : 'fa-clock'}"></i> ${statusLabel}
          </button>
          <button class="facture-delete-btn" type="button" data-invoice-id="${escapeAttr(record.id)}" title="Supprimer facture" ${canDeleteData() ? '' : 'disabled'}>
            <i class="fa-solid fa-trash"></i>
          </button>
        </div>
      </div>
    `;
  }).join('');
}

async function toggleFactureInvoicePaid(invoiceId){
  if(!canEditData()) return alert('Acces refuse');
  const client = getFactureSelectedClient();
  const id = String(invoiceId || '').trim();
  if(!client || !id) return;
  const records = collectFactureTrackingRecords(client);
  const current = records.find(record=>record.id === id);
  if(!current) return;
  const nextStatus = current.status === 'paid' ? 'unpaid' : 'paid';
  const dossiers = Array.isArray(client.dossiers) ? client.dossiers : [];
  const changedEntries = [];
  dossiers.forEach((dossier, dossierIndex)=>{
    const invoiceRecords = Array.isArray(dossier?.factureInvoices) ? dossier.factureInvoices : [];
    let changed = false;
    const nextRecords = invoiceRecords.map(rawRecord=>{
      const record = normalizeFactureTrackingRecord(rawRecord);
      if(!record || record.id !== id) return rawRecord;
      changed = true;
      return {
        ...record,
        status: nextStatus,
        paidAt: nextStatus === 'paid' ? new Date().toISOString() : ''
      };
    });
    if(changed){
      dossier.factureInvoices = nextRecords;
      changedEntries.push({ client, dossier, dossierIndex });
    }
  });
  if(!changedEntries.length) return;
  handleDossierDataChange({ audience: false });
  for(const entry of changedEntries){
    await persistDossierPatchNow({
      action: 'update',
      clientId: Number(entry.client.id),
      dossierIndex: Number(entry.dossierIndex),
      dossier: entry.dossier
    }, { source: 'facture-paid-status' });
  }
  renderFactureTracking();
}

async function deleteFactureInvoice(invoiceId){
  if(!canDeleteData()) return alert('Seul le gestionnaire peut supprimer une facture');
  const client = getFactureSelectedClient();
  const id = String(invoiceId || '').trim();
  if(!client || !id) return;
  const records = collectFactureTrackingRecords(client);
  const current = records.find(record=>record.id === id);
  if(!current) return alert('Facture introuvable');
  if(!await confirmDangerousAction(
    `Envoyer la facture "${current.invoiceRef || '-'}" vers la corbeille ?`,
    { confirmationWord: 'SUPPRIMER' }
  )) return;

  const dossiers = Array.isArray(client.dossiers) ? client.dossiers : [];
  const changedEntries = [];
  const removedInvoices = [];
  dossiers.forEach((dossier, dossierIndex)=>{
    const invoiceRecords = Array.isArray(dossier?.factureInvoices) ? dossier.factureInvoices : [];
    const keptRecords = [];
    let changed = false;
    invoiceRecords.forEach(rawRecord=>{
      const record = normalizeFactureTrackingRecord(rawRecord);
      if(record && record.id === id){
        changed = true;
        removedInvoices.push({
          clientId: Number(client.id),
          clientName: String(client.name || ''),
          dossierIndex,
          dossierLabel: String(dossier?.referenceClient || dossier?.debiteur || `Dossier ${dossierIndex + 1}`),
          record
        });
        return;
      }
      keptRecords.push(rawRecord);
    });
    if(changed){
      dossier.factureInvoices = keptRecords;
      changedEntries.push({ client, dossier, dossierIndex });
    }
  });
  if(!changedEntries.length) return alert('Facture deja supprimee');

  pushRecycleBinEntry('facture_delete', {
    clientId: Number(client.id),
    clientName: String(client.name || ''),
    invoiceId: id,
    record: JSON.parse(JSON.stringify(current)),
    entries: JSON.parse(JSON.stringify(removedInvoices))
  });
  handleDossierDataChange({ audience: false });
  for(const entry of changedEntries){
    await persistDossierPatchNow({
      action: 'update',
      clientId: Number(entry.client.id),
      dossierIndex: Number(entry.dossierIndex),
      dossier: entry.dossier
    }, { source: 'facture-delete' });
  }
  if(currentFacturePreviewRecord?.id === id){
    closeFactureDocumentPreviewModal();
  }
  queuePersistAppState();
  markDeferredRenderDirty('suivi');
  renderFactureTracking();
}

function getFactureProcesVerbalData(){
  if(currentFacturePreviewRecord){
    const trackingData = buildFactureDataFromTrackingRecord(currentFacturePreviewRecord);
    if(trackingData) return trackingData;
  }
  const { client, dossier } = getFactureSelectedDossier();
  const selectedProcedure = getFactureSelectedProcedure(dossier);
  const lines = getFactureProcesVerbalLineEntries();
  const currentTranche = String($('factureDocumentTypeSelect')?.value || 'Tranche 1').trim() || 'Tranche 1';
  const invoiceRef = generateFactureInvoiceNumber(lines, currentTranche);
  const tranches = '';
  const amount = lines.reduce((sum, line)=>sum + (Number(line.amount) || 0), 0);
  const taxeTotal = lines.reduce((sum, line)=>sum + (Number(line.taxe) || 0), 0);
  const vignetteTotal = lines.reduce((sum, line)=>sum + (Number(line.vignette) || 0), 0);
  const medTotal = lines.reduce((sum, line)=>sum + (Number(line.med) || 0), 0);
  const fraisTimbrageTotal = lines.reduce((sum, line)=>sum + (Number(line.fraisTimbrage) || 0), 0);
  const huissierAudienceTotal = lines.reduce((sum, line)=>sum + (Number(line.huissierAudience) || 0), 0);
  const deplacementTotal = lines.reduce((sum, line)=>sum + (Number(line.deplacement) || 0), 0);
  const fraisTotal = vignetteTotal + medTotal + fraisTimbrageTotal + huissierAudienceTotal + deplacementTotal;
  const tva = amount * 0.2;
  const totalTtc = amount + tva;
  const today = typeof formatDateDDMMYYYY === 'function' ? formatDateDDMMYYYY(new Date()) : new Date().toLocaleDateString('fr-FR');
  const clientName = lines[0]?.client?.name || client?.name || '-';
  const debiteurs = [...new Set(lines.map(line=>line.debiteur).filter(Boolean))].join(' | ') || dossier?.debiteur || '-';
  const objet = lines.map(line=>`${line.procedure || 'Procedure'}${line.reference ? ` (${line.reference})` : ''}`).join(' | ')
    || selectedProcedure || tranches || dossier?.procedure || 'Proces-verbal';
  return {
    client,
    dossier,
    lines,
    tranches,
    tranche: currentTranche,
    amount,
    taxeTotal,
    vignetteTotal,
    medTotal,
    fraisTimbrageTotal,
    huissierAudienceTotal,
    deplacementTotal,
    fraisTotal,
    netAPayer: taxeTotal + fraisTotal,
    tva,
    totalTtc,
    invoiceRef,
    today,
    clientName,
    debiteur: debiteurs,
    objet,
    selectedProcedure
  };
}

