  const select = card.querySelector('select[data-field="notifDebiteur"]');
  const dateWrap = card.querySelector('.notif-date-wrap');
  const nbWrap = card.querySelector('.nb-fields-wrap');
  if(!select) return;
  const val = select.value.toLowerCase();
  const isNb = val === 'nb';
